<template>
  <div class="course">
    <div class="position">
       <div class="sl_top">
           <p>特色课</p>
           <p @click="gosearch"><van-icon name="search" /></p>
       </div>
      <!-- 分类排序 -->
       <van-dropdown-menu active-color="#EB6100" title-class="aap">
        <!-- 分类 -->
        <van-dropdown-item title="分类" ref="ok">
          <div class="fenone">
              <p style="font-size:12px;margin-left:20px;">年级</p>
              <ul>
                  <li @click="activeIndex=index" :style="{background:activeIndex==index?'orange':''}" v-for="(item,index) in classname" :key="index">{{ item.name }}</li>
              </ul>
              <p style="font-size:12px;margin-left:20px;">学科</p>
              <ul>
                  <li @click="activeban=index" :style="{background:activeban==index?'orange':''}" v-for="(item,index) in classban" :key="index">{{ item.name }}</li>
              </ul>
          </div>
          
          <van-button style="width:40%;margin-left:5%;height:40px;margin-bottom:20px;background:#fff;border-radius:5px;" color="#666" plain>重置</van-button>
          <van-button @click="oksearch" style="width:40%;margin-left:5%;height:40px;margin-bottom:20px;background:#EB6100;border-radius:5px;" color="#EB6100">确定</van-button>
        </van-dropdown-item>
        <!-- 排序 -->
        <van-dropdown-item title="排序" ref="a2">
          <div class="fentwo">
               <p @click="sortFn">综合排序</p>
               <p @click="sortFnone">最新</p>
               <p @click="sortFntwo">最热</p>
               <p @click="sortFnthree">价格从低到高</p>
               <p @click="sortFnfore">价格从高到底</p>
          </div>
        </van-dropdown-item>
        <van-dropdown-item title="筛选" ref="a3">
          <div class="fenthree">
               <ul>
                   <li v-for="(item,index) in filterList" :key="index">{{ item }}</li>
               </ul>
          </div>
        </van-dropdown-item>
      </van-dropdown-menu>


    </div>
    <div style="width;100%;height:100px;"></div>

    <!-- 列表数据 -->
    <div class="onedeta">
        <ul>
        <li v-for="(item,index) in kelist" :key="index" @click="gocoursedetail(item)">
            <div>{{ item.title }}</div>
            <div>
                <span style="color:#666666;font-size:14px;">{{ item.start_play_date | time }}-</span>
                <span style="color:#666666;font-size:14px;">{{ item.end_play_date | time }} | </span>
                <span style="color:#666666;font-size:14px;">共{{ item.total_periods }}节课时</span>
            </div>
            <div v-for="(s,i) in item.teachers_list" :key="i" class="liqing">
                <img width=20 height=20 :src="s.teacher_avatar" alt="">
                <span>{{ s.teacher_name }}</span>
            </div>
            <div class="peop">
                <p>{{ item.sales_num }}人已报名</p>
                <p>{{ item.price | price }}</p>
            </div>
        </li>
        </ul>
    </div>

  </div>
</template>

<script>
export default {
  name: '',
  data() { 
    return {
        kelist:[],
        keInfo:{
            page:  1,          //第几页开始获取
            limit:  10,         //请求数据数量    
            course_type: 0,    //筛选类型
            classify_id: "" ,   //""
            order_by:  "" ,     //排序方式：（0综合排序，1最新，2最热，3价格由低到高，4价格由高到低）
            attr_val_id: "" ,   //分类id
            is_vip: 0  ,   
        },
        classname:[
            {
              id:1,
              name:"初一"
            },
              {
              id:2,
              name:"初二"
            },
              {
              id:3,
              name:"初三"
            },
              {
              id:4,
              name:"高一"
            },
            {
              id:5,
              name:"高二"
            }
        ],
        classban:[
            {
              id:7,
              name:"高二"
            },
            {
              id:8,
              name:"数学"
            },
            {
              id:9,
              name:"化学"
            },
            {
              id:12,
              name:"物理"
            },
            {
              id:13,
              name:"英语"
            }
        ],
        sortList:[
            {
                id:0,
                name:'综合排序'
            },
            {
                id:1,
                name:'最新'
            },
            {
                id:2,
                name:'最热'
            },
            {
                id:3,
                name:'价格从低到高'
            },
             {
                id:4,
                name:'价格从高到底'
            },
        ],
        filterList: [
            "全部",
            "大班课",
            "小班课",
            "公开课",
            "点播课",
            "面授课",
            "音频课",
            "系统课",
            "图文课",
            "会员课"
        ],
        page:1,   //页数
        limit:10,  //数量
        activeIndex:-1,   //年级选中样式的变化
        activeban:-1,     //学科选中样式的变化
        arr:[],   //收集下标
    }
  },
  props: {

  },
  filters:{
    price(val){
        switch(val){
            case 0:
            return "免费"
        }
    },
    // 转换时间戳
    time(val) {
      var moment = require("moment");
      var aaa = moment(val * 1000).format("MM月DD日 h:mm:ss");
      return aaa;
    }
 },
  components:{
  },
  mounted() {
    // 滑动到底部加载数据
    window.onscroll = () => {
      let scrollTop = document.documentElement.scrollTop;
      let scrollHeight = document.documentElement.scrollHeight;
      let h1 = document.documentElement.clientHeight;
      // console.log(scrollTop + h1, scrollHeight);
      if (scrollTop + h1 >= scrollHeight) {
        this.page++;
        this.$axios.get(`http://120.53.31.103:84/api/app/courseBasis?page=${this.page}&limit=${this.limit}&`).then((res)=>{
           console.log(res)
            res.data.data.list.forEach(v => {
                this.kelist.push(v);
            });
         })
      }
    };
    //  获取课程列表
    //  this.$axios.get(`https://www.365msmk.com/api/app/courseBasis?page=${this.page}&limit=${this.limit}&`).then((res)=>{
    //      console.log(res)
    //      this.kelist=res.data.data.list;
    //      console.log(this.kelist)
    //  }),
    //  分类数据标题
    //  this.$axios.get("https://www.365msmk.com/api/app/courseClassify").then((res)=>{
    //     console.log(res)
    //     this.classname=res.data.data.attrclassify[0].child
    //     this.classban=res.data.data.attrclassify[1].child
    //     console.log(this.classname)
    //  }),
     this.ajaxCourseList()   //调用课程列表数据

  },
  methods:{
    // 点击改变样式
    changecolor(index){
       this.activeIndex=index
    },
    // 获取课程列表数据
    async ajaxCourseList(){
       let { data:res }=await this.$axios.get("http://120.53.31.103:84/api/app/courseBasis",{
           params:this.keInfo
       })
       this.kelist=res.data.list;
       console.log(this.kelist)
    },
    // 点击分类的确定进行分类筛选调取数据
    oksearch(){
        let arr=[]   //收集
        // let classnameid=this.classname[this.activeIndex].id
        // let classbanid=this.classban[this.activeban].id
        // console.log(classbanid)
        if(this.activeIndex!=-1){
            let classnameid=this.classname[this.activeIndex].id
            arr.push(classnameid)
        }
        if(this.activeban!=-1){
             let classbanid=this.classban[this.activeban].id
             arr.push(classbanid)
        }
        console.log(arr)
        arr.join(",")
        this.keInfo.attr_val_id=arr.join(",")
        console.log(this.keInfo.attr_val_id)
        this.ajaxCourseList()
        this.$refs.ok.toggle()

    },
    // 点击跳到课程详情coursedetail
    gocoursedetail(item){
        this.$router.push({
            path:'/coursedetail',
            query:{
                id:item.id
            }
        })
    },
        // 综合排序
    sortFn(){
        this.keInfo.order_by=0;
         this.ajaxCourseList()   //更新课程列表数据
         this.$refs.a2.toggle()
    },
    // 最新
    sortFnone(){
        this.keInfo.order_by=1;
         this.ajaxCourseList()   //更新课程列表数据
         this.$refs.a2.toggle()
    },
    // 最热
     sortFntwo(){
        this.keInfo.order_by=2;
         this.ajaxCourseList()   //更新课程列表数据
         this.$refs.a2.toggle()
    },
    // 从小到大排序
     sortFnthree(){
        this.keInfo.order_by=3;
         this.ajaxCourseList()   //更新课程列表数据
         this.$refs.a2.toggle()
    },
    // 从大到小排序
     sortFnfore(){
        this.keInfo.order_by=4;
         this.ajaxCourseList()   //更新课程列表数据
         this.$refs.a2.toggle()
    },
    // 点击跳到搜索页面
    gosearch(){
        this.$router.push({
            path:'/search'
        })
    }
   

  },
 }
</script>

