<template>
  <div>
    <!-- 顶部input搜索框 -->
    <div class="sl_search_head">
        <p @click="fan"><van-icon name="arrow-left" /></p>
        <p class="sl_input">
            <input v-model="inputText" @input="input" type="text" placeholder="请输入搜索内容">
        </p>
        <p style="color:#DBD2DA" v-show="toogle">取消</p>
        <p style="color:#000" v-show="toook" @click="search">搜索</p>
    </div>
    <!-- 搜索后的历史记录 -->
    <div class="sl_search_history">
        <p>历史搜索</p>
        <p @click="detelehis"><van-icon name="delete" /></p>
    </div>
    <!-- 根据input框中的搜索内容实时搜索的数据渲染列表 -->
    <div class="onedeta" v-show="searchlistshow">
        <ul>
        <li v-for="(item,index) in searchlist" :key="index">
            <div>{{ item.title }}</div>
            <div>
                <span style="color:#666666;font-size:14px;">{{ item.start_play_date | time }}-</span>
                <span style="color:#666666;font-size:14px;">{{ item.end_play_date | time }} | </span>
                <span style="color:#666666;font-size:14px;">共{{ item.total_periods }}节课时</span>
            </div>
            <div v-for="(s,i) in item.teachers_list" :key="i" class="liqing">
                <img width=20 height=20 :src="s.teacher_avatar" alt="">
                <span>{{ s.teacher_name }}</span>
            </div>
            <div class="peop">
                <p>{{ item.sales_num }}人已报名</p>
                <p>{{ item.price | price }}</p>
            </div>
        </li>
        </ul>
    </div>
    <!-- 搜索历史的一个渲染页面 -->
    <div class="search_history_for">
        <ul>
            <li @click="hiscon(index,item)" v-for="(item,index) in history" :key="index">{{ item }}</li>
        </ul>
    </div>

  </div>
</template>

<script>
export default {
  name: '',
  data() { 
    return {
        inputText:'',
        toogle:true,
        toook:false,
        searchlist:[],
        searchlistshow:false,
        history:[]
    }
  },
  props: {

  },
  filters:{
     price(val){
        switch(val){
            case 0:
            return "免费"
        }
    },
    // 转换时间戳
    time(val) {
      var moment = require("moment");
      var aaa = moment(val * 1000).format("MM月DD日 h:mm:ss");
      return aaa;
    }
 },
  components:{
  },
  created(){
    let his=window.localStorage.getItem("history")
    if(his){
        this.history=JSON.parse(his)
    }
  },
  mounted() {
    //  this.search()

  },
  methods:{
    // 正在输入是将取消变为确认，input框为空时在变为取消
    input(){
          this.toogle=false,
          this.toook=true
          this.searchlistshow=true
          if(this.inputText==''){
              this.searchlistshow=false
          }
    },
    // 点击搜索时调取接口并渲染到页面
    // async search(){
    //     let { data:res } = await this.$axios.get(`http://120.53.31.103:84/api/app/courseBasis?limit=10&page=1&course_type=0&keywords=${this.inputText}`)
    //     console.log(res)
    //     this.searchlist=res.data.list;
    // }
    search(){
        this.$axios.get(`http://120.53.31.103:84/api/app/courseBasis?limit=10&page=1&course_type=0&keywords=${this.inputText}`).then((res)=>{
             console.log(res)
             this.searchlist=res.data.data.list;
        })
        let arr=[]
        let his=window.localStorage.getItem("history")
        if(his){
            arr=JSON.parse(his)
        }
        arr.push(this.inputText)
        this.history=arr
        window.localStorage.setItem("history",JSON.stringify(arr))
    },
    fan(){
        this.$router.go(-1)
    },
    detelehis(){
        this.history=[]
        window.localStorage.removeItem("history")
    },
    // 点击搜索历史将历史数据放到input中，进行再次搜索
    hiscon(index){
        this.inputText=this.history[index]
        this.toogle=false
        this.toook=true
        this.searchlistshow=true
        
     
    }
  


  },
 }
</script>

<style scoped>
*{
    margin:0px;
    padding:0px;
}
.sl_search_head{
    width:100%;
    height:50px;
    display: flex;
    justify-content: center;
    align-items: center;
    border-bottom:1px solid #EAEAEA;
}
.sl_input{
    width:65%;
    margin:0 5%;
}
.sl_search_head>.sl_input>input{
    width:100%;
    height:30px;
    border-radius:20px;
    border:none;
    outline:none;
    background-color: #E4E7ED;
    font-size:14px;
    padding-left:20px;
    box-sizing: border-box;
}
.sl_search_history{
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-top:40px;
}
.sl_search_history>p:nth-of-type(1){
    margin-left:20px;
    font-size:14px;
    color:#000;
}
.sl_search_history>p:nth-of-type(2){
    margin-right:20px;
    color:#C3C3C3;
    font-size:16px;
}
.search_history_for>ul{
    display: flex;
    flex-wrap: wrap;
}
.search_history_for>ul>li{
    background-color: #F7F7F7;
    border-radius:10px;
    margin-left:20px;
    margin-top:20px;
    font-size:12px;
    color:#333333;
}
.onedeta>ul{
  height:100%;
  background-color: #F0F2F5;
}
.onedeta{
   background-color: #F0F2F5;
   margin-top:10px;
   position: absolute;
   top:50px;
   left:0;
   right:0;
  
}
.onedeta>ul>li{
  width:90%;
  height:200px;
  border-radius:10px;
  background-color: #fff;
  margin-left:5%;
  margin-bottom:10px;
  padding:20px 14px;
  box-sizing: border-box; 
  position: relative;
}
.liqing{
    height:60px;
    display: flex;
    align-items: center;
}
.liqing>img{
    margin-right:10px;
}
.liqing>span{
    color:#8C8C8C;
}
.peop{
    display: flex;
    justify-content: space-between;
    width:100%;
    height:40px;
    align-items: center;
    border-top:1px solid #F5F5F5;

    
}
.peop>p:nth-of-type(1){
   color:#8C8C8C;
}
</style>