<template>
  <div class="login">
    <!-- 顶部图片 -->
    <div class="sl_img">
        <img width=60% height=60 src="https://msmk2019.oss-cn-shanghai.aliyuncs.com/uploads/image/2019pILfAg7Avr1567732916.png" alt="">
    </div>
    <!-- 信息区域 -->
    <div class="xinxi">
        <p :style="{borderBottom:activeIndex==1?'1px solid #FC5500':'',marginRight:'30px'}" @click="activeIndex=1" >
            <input type="text" placeholder="请输入手机号" v-model="tele" @blur="blurFn">
            <span @click="loginFn" class="yanzhengma" v-show="isCodeClick">获取验证码</span>
            <span class="yanzhengma" style="color:#999" v-show="!isCodeClick">获取验证码({{ sum }})</span>
        </p>
        <p @click="activeIndex=2" :style="{borderBottom:activeIndex==2?'1px solid #FC5500':'',marginRight:'30px'}"><input @blur="blurFn" type="text" placeholder="请输入短信验证码" v-model="sms"></p>
        <div class="passlogin">
            <p>*未注册的手机号将自动注册</p>
            <p style="margin-right:30px;" @click="passlogin">使用密码登录</p>
        </div>
    </div>
    <!-- 登录按钮 -->
    <div class="denglu">
        <van-button color="linear-gradient(to right, #FF9147, #FC5500)" block round  @click="denglu">登录</van-button>
    </div>
  </div>
</template>

<script>
export default {
  name: '',
  data() { 
    return {
        tele:"",
        sms:'',
        codeText:"",
        sum:60,   //倒计时时间
        isCodeClick:true,   //控制是否可以点击验证码，灰色不能，橘色能
        activeIndex:-1
        
    }
  },
  props: {

  },
  components:{
  },
  mounted() {

  },
  methods:{
    // 验证码
    loginFn(){
        let phone=/^1[3456789]\d{9}$/;  // 手机号格式验证正则
        let phoneone=phone.test(this.tele)   //判断目前你输入的手机号是否符合规则
        if(phoneone){
            this.isCodeClick=false;
            let timer=setInterval(()=>{
                this.sum--;
                if(this.sum==0){
                    this.sum=60;
                    this.isCodeClick=true;
                    clearInterval(timer)
                }
            },1000)
        }else{
            this.$Toast('请输入正确手机号');
            return
        }
      this.$http.post('/api/app/smsCode',{mobile:this.tele,sms_type:'login'}).then((res)=>{
        console.log(res)
        this.$Toast(res.data.msg)
      })
    },
    // 点击登录
    denglu(){
        this.$http.post('/api/app/login',{mobile:this.tele,sms_code:this.sms,type:2,client:1}).then((res)=>{
            console.log(res)
            if(res.data.code=="200"){
                window.localStorage.setItem("adminToken",JSON.stringify(res.data.data.remember_token));
                window.localStorage.setItem("userid",JSON.stringify(res.data.data.id));
                if(res.data.data.is_new == 2) {
                    this.$router.push('/zpwd')
                } else {
                    this.$router.push('/index')
                }
            }
           

        })
    },
    // 切换到密码登录
    passlogin(){
        this.$router.push({
            path:"/denglogin"
        })
    },
    blurFn(){
        this.activeIndex=-1
    },
  
  },
 }
</script>

<style scoped>
.login{
    height:100%;
    /* background-color: orange; */
}
.sl_img{
    text-align: center;
    width:100%;
    box-sizing:border-box;
}
.sl_img>img{
    margin:60px 0;
}
.passlogin{
    display: flex;
    justify-content: space-between;
}
.xinxi{
    margin-left:10%;
}
.xinxi>p{
    padding-bottom:15px;
}
.xinxi>p>input{
    border:none;
    outline:none;
    color:#757575;
    font-size:14px;
}
.yanzhengma{
    color:#FC5500;
    font-size:12px;
    margin-left:36px;
}
.passlogin{
    color:#999999;
    font-size:12px;
}
.denglu{
    margin-top:40px;
    margin-left:30px;
    margin-right:30px;

}
</style>