<template>
  <div class="otoplan">
      <div class="headblue">
        <!-- 蓝色头部信息 -->
        <p style="margin-right:36%;margin-left:10px;"><van-icon name="arrow-left" @click="gooto"/></p>
        <p>预约课程</p>
      </div>
      <!-- 蓝色老师详细信息 -->
      <div class="box">
          <div class="headbluefff">
              <div><img style="border-radius:50px;" width=40 height=40 :src="teachlist.avatar" alt=""></div>
              <div>
                <p class="teachername">{{ teachlist.teacher_name }}</p>
                <p class="teacherage">{{ teachlist.sex |sexF }}{{ teachlist.age }}年教龄</p>
              </div>
              <div><button @click="goteacher(teachlist.id)">查看详情</button></div>
          </div>
      </div>
      <!-- 选择时间 -->
      <p class="timer">选择时间<span>(北京时间)</span></p>
      <!-- 时间 -->
      <div class="iscrolltime" id="iscrolltime">
        <ul>
          <li @click="tooglcolor(index)" :style="{color:activeIndex==index?'orange':'#666',borderBottom:activeIndex==index?'5px solid blue':''}" v-for="(item,index) in timelist" :key="index">
            <p>周一</p>
            <span>{{ item }}</span>
          </li>
        </ul>
      </div>
      <!-- 图片暂无信息 -->
      <div class="sl_tu">
        <img src="../../public/hui.png" alt="">
        <p>暂无信息</p>
      </div>
      


      <div class="denglu">
        <van-button block color="#FC5500">立即预约</van-button>
    </div>
  </div>
</template>
<script>
import Iscroll from "iscroll";
export default {
  name: "",
  data() {
    return {
      teachlist:{},
      timelist:[],
      activeIndex:0
    };
  },
  props: {},
  components: {},
    filters:{
     sexF(val){
         switch(val){
             case 0:
                 return "男";
            case 1:
                return "女"
         }
     }
  },
  mounted() {
    //阻止浏览器的默认行为,九宫格部分左右滑动
    document.addEventListener(
      "touchmove",
      function(ev) {
        ev.preventDefault();
      },
      { passive: false }
    );
    // 导航滑动
    let iscroll = new Iscroll("#iscrolltime", {
      scrollX: true,
      scrollY: false
    });
    // 时间数据讲师id必须填写
     this.$axios.get(`https://www.365msmk.com/api/app/teacher/${this.$route.query.id}`).then((res)=>{
       console.log(res)
       this.teachlist=res.data.data.teacher;
       console.log(this.teachlist)
     })
    // console.log(this.$route.query.id)
    // 时间接口
    this.$axios.post("https://www.365msmk.com/api/app/teacher/invite",{
      is_next: 0,
      teacher_id: this.$route.query.id,
      week_day: 1,
    }).then((res)=>{
      console.log(res)
      this.timelist=res.data.data.weekDateList;
      console.log(this.timelist)
    })
   
  },
  methods: {
    gooto(){
      this.$router.go(-1)
    },
    // 点击头部查看详情跳到teacher讲师详情页面
    goteacher(id){
      this.$router.push({
        path:"/teacher",
        query:{
           id:id
        }
      })
    },
    tooglcolor(index){
      this.activeIndex=index
    }
  }
};
</script>
<style scoped>
