    height:100%;
    background-color: #F0F2F5;
}
.headblue{
  width:100%;
  height:100px;
  background: linear-gradient(#5EAAF8, #5286E8);
  color:#fff;
  font-size:20px;
  display: flex;
  /* justify-content: center; */
  position: relative;
}
.headblue>p{
  margin-top:10px;
}

