    display: flex;
    color:#EA7A2F;
    justify-content: space-around;
    /* border:1px solid #ccc; */
}
.btndiv>p{
    background-color: #FFE4D3;
    padding:4px 10px;
    border-radius:20px;
    font-size:12px;
}
.headbluefff>div:nth-of-type(2){
  width:60%;
}
.headbluefff>div>img{
  margin:0 10px;
}
.headbluefff>div>button{
  width:80px;
  height:30px;
